  name          = EXCLUDED.name,
  "countryCode" = COALESCE(EXCLUDED."countryCode", registry_authorities."countryCode"),
  jurisdiction  = COALESCE(EXCLUDED.jurisdiction,  registry_authorities.jurisdiction),
  "updatedAt"   = NOW()
WHERE
  registry_authorities.name != EXCLUDED.name
  OR registry_authorities."countryCode" IS DISTINCT FROM EXCLUDED."countryCode"
  OR registry_authorities.jurisdiction IS DISTINCT FROM EXCLUDED.jurisdiction;
